export function nextId(prefix, currentLength) {
    return `${prefix}-${String(currentLength + 1).padStart(3, "0")}`;
}
export function appendAudit(acao, entidade, entidadeId, detalhes, usuario = "system") {
    db.auditLog.unshift({
        id: nextId("LOG", db.auditLog.length),
        data: new Date().toISOString().replace("T", " ").slice(0, 16),
        usuario,
        acao,
        entidade,
        entidadeId,
        detalhes,
    });
}
